#include<bits/stdc++.h>
using namespace std;
int a[100010];
const double eps=1e-6;
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        a[i]++;
    }
    sort(a+1,a+1+n);
    for(double i=a[1]+1;i>=eps;i-=eps)
    {
        bool flag=true;
        for(int j=1;j<=n;j++)
        {
            if((int)(a[j]/i)*i<=a[j]-1)
            {
                flag=false;
                break;
            }
        }
        if(flag)
        {
            printf("%.6lf",i);
            return 0;
        }
    }
    return 0;
}
